class Solution:
    def numberOfBeautifulIntegers(self, low: int, high: int, k: int) -> int:
        count = 0
        for num in range(low, high + 1):
            if num % k == 0:
                even = 0
                odd = 0
                for ch in str(num):
                    digit = int(ch)
                    if digit % 2 == 0:
                        even += 1
                    else:
                        odd += 1
                if even == odd:
                    count += 1
        return count
